export function getCountrySpots(country: string): Spot[] {
  const cities = COUNTRY_CITIES[country] ?? [];
  return cities.flatMap((code) =>
    (CITY_SPOTS[code] ?? []).map((spot) => ({ ...spot, city: CODE_TO_CITY[code] ?? code }))
  );
}
